def cal_priority(status, num_neighboring_machine, processing_time, start_time, delivery_time, available_time, num_neighboring_operation, utilization, processing_tm):
    if isinstance(available_time, (list, tuple)):
        current_time = min(available_time) if available_time else 0.0
    else:
        current_time = available_time if available_time is not None else 0.0

    # Calculate slack
    slack = delivery_time - current_time - processing_time

    # Base priority using EDD with slack penalty
    if slack >= 0:
        base_priority = delivery_time + 0.001 * start_time
    else:
        # Tardiness-sensitive penalty: amplify priority for negative slack
        base_priority = delivery_time + abs(slack) * 0.5 + 0.001 * start_time

    # Utilization factor: higher utilization increases priority
    util_factor = utilization if utilization > 0 else 0.5
    util_penalty = util_factor * 0.1

    # Processing time variability: lower processing_tm reduces priority for urgent tasks
    if processing_tm <= 0:
        var_penalty = 0.0
    else:
        var_penalty = processing_tm * 0.1

    # Machine availability weighting: normalized availability gap
    if isinstance(available_time, (list, tuple)) and available_time:
        min_avail = min(available_time)
        availability_gap = current_time - min_avail
        # Normalize by processing time to avoid scale issues
        if processing_time > 0:
            norm_gap = availability_gap / processing_time
        else:
            norm_gap = availability_gap
        avail_weight = -norm_gap * 0.1
    else:
        avail_weight = 0.0

    # Balanced machine count weight: positive contribution when few machines, negative when many
    if num_neighboring_machine > 0:
        # Use reciprocal with dampening factor to avoid over-penalizing
        if num_neighboring_machine <= 3:
            num_machines_weight = 0.2 / num_neighboring_machine  # positive to increase priority
        else:
            num_machines_weight = -0.05 * num_neighboring_machine  # negative to decrease priority
    else:
        num_machines_weight = 0.0

    # Explicit machine-task eligibility penalty: penalize tasks with limited options
    eligibility_factor = 0.0
    if num_neighboring_machine > 0 and num_neighboring_operation > 0:
        ratio = num_neighboring_operation / num_neighboring_machine
        if ratio > 1:
            eligibility_factor = (ratio - 1) * 0.2  # higher penalty for more restricted tasks
        else:
            eligibility_factor = 0.0

    # Combine all components
    priority = (base_priority + util_penalty + var_penalty + avail_weight + num_machines_weight + eligibility_factor)

    # Ensure non-negative
    if priority < 0:
        priority = 0.0

    result = priority
    return priority

def cal_priority(status, num_neighboring_machine, processing_time, start_time, delivery_time, available_time, num_neighboring_operation, utilization, processing_tm):
    if isinstance(available_time, (list, tuple)):
        current_time = min(available_time) if available_time else 0.0
    else:
        current_time = available_time if available_time is not None else 0.0

    # Calculate slack
    slack = delivery_time - current_time - processing_time

    # Dynamic weight based on slack threshold and utilization
    if utilization > 0.8:
        slack_weight = 0.6  # Aggressive penalty for negative slack when highly utilized
    elif utilization > 0.5:
        slack_weight = 0.4
    else:
        slack_weight = 0.2

    # Base priority using dynamic slack-based EDD
    if slack >= 0:
        base_priority = delivery_time + 0.001 * start_time
    else:
        # Tardiness-sensitive penalty with dynamic weight
        base_priority = delivery_time + abs(slack) * slack_weight + 0.001 * start_time

    # Dynamic utilization factor
    util_factor = min(utilization, 1.0) if utilization > 0 else 0.5
    util_penalty = util_factor * 0.15

    # Processing time variability
    if processing_tm <= 0:
        var_penalty = 0.0
    else:
        # Adjusted to reduce impact for urgent tasks
        var_penalty = processing_tm * (0.05 * (1 - min(utilization, 1.0)))

    # Machine availability weighting with dynamic gap normalization
    if isinstance(available_time, (list, tuple)) and available_time:
        min_avail = min(available_time)
        availability_gap = current_time - min_avail
        if processing_time > 0:
            norm_gap = availability_gap / (processing_time + 1e-10)
        else:
            norm_gap = availability_gap
        # Dynamic weight based on gap severity
        gap_weight = 0.15 if norm_gap > 2 else 0.1
        avail_weight = -norm_gap * gap_weight
    else:
        avail_weight = 0.0

    # Balanced machine count weight with dynamic adjustment
    if num_neighboring_machine > 0:
        if num_neighboring_machine <= 3:
            num_machines_weight = 0.2 / (num_neighboring_machine + 1e-10)
        else:
            num_machines_weight = -0.03 * num_neighboring_machine * (1 + utilization)
    else:
        num_machines_weight = 0.0

    # Explicit eligibility penalty with processing time ratio
    eligibility_factor = 0.0
    if num_neighboring_machine > 0 and num_neighboring_operation > 0:
        ratio = num_neighboring_operation / (num_neighboring_machine + 1e-10)
        if ratio > 1:
            eligibility_factor = (ratio - 1) * 0.2
        else:
            eligibility_factor = 0.0

    # Incorporate machine-task processing time ratio (Suggestion 2)
    # Favors assignments where task's processing time is shortest on this machine
    pt_ratio_penalty = 0.0
    if processing_time > 0 and processing_tm > 0:
        pt_ratio = processing_tm / processing_time
        if pt_ratio < 1:
            pt_ratio_penalty = -pt_ratio * 0.1  # Lower priority for short relative processing time (better match)
        else:
            pt_ratio_penalty = pt_ratio * 0.05  # Higher priority for poor match

    # Look-ahead term for next operation eligible machines (Suggestion 3)
    look_ahead_penalty = 0.0
    if num_neighboring_operation > 0:
        if num_neighboring_operation <= 2:
            look_ahead_penalty = 0.3  # Increase priority for bottleneck next operation
        elif num_neighboring_operation <= 5:
            look_ahead_penalty = 0.1
        else:
            look_ahead_penalty = -0.05  # Reduce priority for many options

    # Combine all components
    priority = (base_priority + util_penalty + var_penalty + avail_weight + 
                num_machines_weight + eligibility_factor + pt_ratio_penalty + look_ahead_penalty)

    # Ensure non-negative
    if priority < 0:
        priority = 0.0

    result = priority
    return priority
